import type { FC } from 'react';
import React from 'react';
import { ConfigProvider } from '../../config-provider';
import type { TagPropSize } from '../../tag';
import { Tag } from '../../tag';
import Tooltip from '../../tooltip';
import { forwardHTMLRef } from '../../util/forwardRef';
import { useOrganizationNameTagLocale } from './locales';

export interface OrganizationNameTagProps extends React.PropsWithChildren<unknown> {
  /**
   * 标签的尺寸
   * @defaultValue `extra-small`
   */
  size?: TagPropSize;
}

const OrganizationNameTagUI = forwardHTMLRef<OrganizationNameTagProps, 'span'>(
  ({ size = 'extra-small', children, ...props }, ref) => (
    <Tag {...{ ...props, ref, size, color: 'blue' }}>{children}</Tag>
  ),
);

if (__DEV__) {
  OrganizationNameTagUI.displayName = 'OrganizationNameTagUI';
}

const Identity: FC = ({ children }) => <>{children}</>;

const OrganizationNameExternalTag = forwardHTMLRef<OrganizationNameTagProps, 'span'>((props, ref) => {
  const locale = useOrganizationNameTagLocale();

  if (!locale) {
    return <></>;
  }

  return (
    <ConfigProvider textOverflowPopperSidecar={Identity}>
      <Tooltip title={locale.externalTooltip}>
        <OrganizationNameTagUI ref={ref} {...props}>
          {locale.external}
        </OrganizationNameTagUI>
      </Tooltip>
    </ConfigProvider>
  );
});

if (__DEV__) {
  OrganizationNameExternalTag.displayName = 'OrganizationNameExternalTag';
}

export const OrganizationNameTag = forwardHTMLRef<OrganizationNameTagProps, 'span'>(({ children, ...props }, ref) => {
  if (children) {
    // '' 0 false null undefined
    return (
      <OrganizationNameTagUI ref={ref} {...props}>
        {children}
      </OrganizationNameTagUI>
    );
  }
  return <OrganizationNameExternalTag ref={ref} {...props} />;
});

if (__DEV__) {
  OrganizationNameTag.displayName = 'OrganizationNameTag';
}
